select s.id, s.stock_code, s.stock_name, s.market, s.industry_name, s.pe_ratio, s.total_market_cap, s.circ_market_cap, s.current_price, s.change_rate, s.price_change, s.turnover_rate, s.volume_ratio, s.amplitude, s.turnover_amount, s.circulating_shares, s.create_by, s.create_time, s.update_by, s.update_time, s.remark from stock s
and s.stock_code = #{stockCode} and s.stock_name like concat('%', #{stockName}, '%') and s.market = #{market}
and EXISTS ( select 1 from stock_plate_stock sps inner join stock_plate sp on sps.plate_id = sp.id where sps.stock_id = s.id and sp.plate_type = 'INDUSTRY' and (sp.id = #{industryId} or FIND_IN_SET(#{industryId}, sp.ancestors)) )
and EXISTS ( select 1 from stock_plate_stock sps2 inner join stock_plate sp2 on sps2.plate_id = sp2.id where sps2.stock_id = s.id and sp2.plate_type = 'CONCEPT' and sp2.id in
#{conceptId}
)
and EXISTS ( select 1 from stock_group_stock sgs where sgs.stock_id = s.id and sgs.group_id = #{groupId} )

